import{_ as a,o as e,c as n,a2 as i}from"./chunks/framework.KT0ECV7t.js";const g=JSON.parse('{"title":"LangChain 学习笔记","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"learn/summary-langchain.md","filePath":"learn/summary-langchain.md","lastUpdated":null}'),s={name:"learn/summary-langchain.md"};function o(r,t,l,h,d,p){return e(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="langchain-学习笔记" tabindex="-1">LangChain 学习笔记 <a class="header-anchor" href="#langchain-学习笔记" aria-label="Permalink to &quot;LangChain 学习笔记&quot;">​</a></h1><p>持续更新中。记录 LangChain 核心概念、常用模式和踩坑日记。</p><h2 id="核心组件速查" tabindex="-1">核心组件速查 <a class="header-anchor" href="#核心组件速查" aria-label="Permalink to &quot;核心组件速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>用途</th><th>关键 API</th></tr></thead><tbody><tr><td>Model</td><td>统一 LLM 接口</td><td><code>ChatDeepSeek(model=&quot;deepseek-chat&quot;)</code></td></tr><tr><td>Tool</td><td>包装函数供 Agent 调用</td><td><code>@tool</code> 装饰器或 MCP 工具</td></tr><tr><td>Agent</td><td>决策循环</td><td><code>create_agent(model, tools, prompt)</code></td></tr><tr><td>Memory</td><td>对话记忆</td><td><code>InMemorySaver()</code> 作为 checkpointer</td></tr></tbody></table><h2 id="新版-vs-旧版-api" tabindex="-1">新版 vs 旧版 API <a class="header-anchor" href="#新版-vs-旧版-api" aria-label="Permalink to &quot;新版 vs 旧版 API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>旧版（废弃）</th><th>新版（推荐）</th></tr></thead><tbody><tr><td><code>initialize_agent()</code></td><td><code>create_agent()</code></td></tr><tr><td><code>.run()</code></td><td><code>.invoke()</code> / <code>.ainvoke()</code></td></tr><tr><td><code>from langchain.tools</code></td><td><code>from langchain_core.tools</code></td></tr></tbody></table><h2 id="六种-agent-模式" tabindex="-1">六种 Agent 模式 <a class="header-anchor" href="#六种-agent-模式" aria-label="Permalink to &quot;六种 Agent 模式&quot;">​</a></h2><p>模式按复杂度递增。大多数需求用前两种就够了。</p><ol><li><strong>Augmented LLM</strong> — 给模型加工具，最基础</li><li><strong>Prompt Chaining</strong> — 多个步骤串联（概要 → 草稿 → 校验 → 输出）</li><li><strong>Routing</strong> — 根据问题类型分发给不同处理</li><li><strong>Parallelization</strong> — 并行处理</li><li><strong>Orchestrator</strong> — 主 Agent 协调子 Agent</li><li><strong>Evaluator-Optimizer</strong> — 迭代改进</li></ol><h2 id="常见踩坑" tabindex="-1">常见踩坑 <a class="header-anchor" href="#常见踩坑" aria-label="Permalink to &quot;常见踩坑&quot;">​</a></h2><p><strong>1. Agent 无限循环</strong></p><p>原因：Agent 反复调同一个工具得不到满意结果。解决：system_prompt 设上限。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">system_prompt </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&quot;&quot;... After calling a tool 3 times without progress,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">explain what you know so far and ask the user for guidance.&quot;&quot;&quot;</span></span></code></pre></div><p><strong>2. 工具返回了非 JSON 字符串</strong></p><p>Agent 读工具结果时如果格式不对，LLM 可能误解。返回 JSON 时确保格式正确。</p><p><strong>3. 忘记加 checkpointer</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">checkpointer </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> InMemorySaver()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">agent </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> create_agent(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">checkpointer</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">checkpointer)</span></span></code></pre></div><p>没有 checkpointer，Agent 不会记住前面的对话。</p><p><strong>4. MCP 工具的同步/异步兼容</strong></p><p>MCP 工具默认是 async，LangGraph 有时候要 sync。用法见 <a href="/learn/mcp/0003-mcp-langchain.html">Lesson 3</a>。</p><h2 id="推荐阅读" tabindex="-1">推荐阅读 <a class="header-anchor" href="#推荐阅读" aria-label="Permalink to &quot;推荐阅读&quot;">​</a></h2><ul><li><a href="https://github.com/jcran/effective-agents-langchain" target="_blank" rel="noreferrer">Effective Agent Patterns with LangChain (GitHub)</a></li><li><a href="https://python.langchain.com/docs/" target="_blank" rel="noreferrer">LangChain 官方文档</a></li></ul>`,22)])])}const k=a(s,[["render",o]]);export{g as __pageData,k as default};
